				\begin{document}$$\mathop {\hbox{min} }\limits_{P} \sum\limits_{{k=1}}^{{K - 1}} {(\left| {{x_{k+1}} - {x_k}} \right|+\left| {{y_{k+1}} - {y_k}} \right|)}$$\end{document}

